1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block unchanged (still-life)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(new Set(result.map(c => c.join(",")))).toEqual(
17	      new Set([[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")))
18	    );
19	  });
20	  it("should rotate a vertical blinker into a horizontal blinker", () => {
21	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
22	    expect(new Set(result.map(c => c.join(",")))).toEqual(
23	      new Set([[-1, 1], [0, 1], [1, 1]].map(c => c.join(",")))
24	    );
25	  });
26	  it.todo("should kill the center of a filled 3x3 and produce corners-only pattern (overpopulation)");
27	  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
28	  it.todo("should handle negative coordinates correctly");
29	});
30

1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
12	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const liveKeys = new Set(liveCells.map(cellKey));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of liveCells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const key = cellKey(neighbor);
22	      const entry = neighborCounts.get(key);
23	      if (entry) {
24	        entry.count += 1;
25	      } else {
26	        neighborCounts.set(key, { cell: neighbor, count: 1 });
27	      }
28	    }
29	  }
30	
31	  const survivors: Cell[] = [];
32	  for (const [key, { cell, count }] of neighborCounts) {
33	    if (survives(liveKeys.has(key), count)) {
34	      survivors.push(cell);
35	    }
36	  }
37	
38	  return survivors;
39	}
