it("should kill the center of a filled 3x3 and produce corners-only pattern (overpopulation)", () => {
  const result = nextGeneration([
    [0, 0], [1, 0], [2, 0],
    [0, 1], [1, 1], [2, 1],
    [0, 2], [1, 2], [2, 2],
  ]);
  expect(new Set(result.map(c => c.join(",")))).toEqual(
    new Set([
      [0, 0], [2, 0], [0, 2], [2, 2],
      [-1, 1], [1, -1], [3, 1], [1, 3],
    ].map(c => c.join(",")))
  );
});
